const megaRaw = $('Query All').first().json;
let mega = {};
try { mega = megaRaw.mega || megaRaw; } catch(e) {}

let kpi = null;
try { kpi = mega.kpi || null; delete mega.kpi; } catch(e) {}

let briefRaw = {};
try { briefRaw = mega.briefing || {}; delete mega.briefing; } catch(e) {}

const stats = mega.stats || {};
const sitrepOpps = mega.sitrep_opps || [];
const deadlineSoon = sitrepOpps.filter(o => o.response_deadline && Math.ceil((new Date(o.response_deadline) - new Date()) / 86400000) <= 30);
const topPursue = sitrepOpps.filter(o => o.gda_label === 'PURSUE').slice(0, 5);

let briefHeadlines = [];
try {
  const bh = briefRaw.headlines;
  briefHeadlines = typeof bh === 'string' ? JSON.parse(bh) : (Array.isArray(bh) ? bh : []);
} catch(e) {}
const briefSummary = briefRaw.summary || null;

const criticalActions = [
  deadlineSoon.length > 0 ? `${deadlineSoon.length} PURSUE/EVALUATE opp${deadlineSoon.length > 1 ? 's' : ''} due within 30 days — triage required` : null,
  topPursue.length > 0 ? `Top pursue: ${topPursue.map(o => (o.opp_title || '').substring(0, 40)).join('; ')}` : null,
  stats.deadlines_14d > 0 ? `${stats.deadlines_14d} response deadline${stats.deadlines_14d > 1 ? 's' : ''} within 14 days` : null
].filter(Boolean);

const worldNews = briefHeadlines.slice(0, 6).map(h => ({
  title: h.title || h.topic || 'Defense Intel',
  topic: h.title || h.topic || 'Defense Intel',
  status: h.status || 'yellow',
  summary: h.summary || h.why_you_care || h.description || '',
  why_you_care: h.why_you_care || h.summary || '',
  url: h.url || h.source || null,
  source: h.url || h.source || null
}));

const marketSignals = [
  stats.deadlines_14d > 0 ? { indicator: 'Deadline Pressure', status: 'red', update: `${stats.deadlines_14d} response deadline(s) within 14 days`, takeaway: 'Immediate triage required', source: null } : null,
  deadlineSoon.length > 0 ? { indicator: 'Pipeline Velocity', status: 'yellow', update: `${deadlineSoon.length} PURSUE/EVALUATE opps due within 30 days`, takeaway: 'Review capture readiness and teaming', source: null } : null,
  stats.pursue > 0 ? { indicator: 'Active Pursuit Count', status: 'green', update: `${stats.pursue} opps in PURSUE — ${((stats.pipeline_value||0)/1e6).toFixed(1)}M total pipeline`, takeaway: 'Pipeline healthy — maintain momentum', source: null } : null
].filter(Boolean);

const dodItems = briefHeadlines.slice(0, 4).map(h => ({
  topic: h.title || h.topic || 'Intel Update',
  status: h.status || 'green',
  update: h.summary || h.description || '',
  takeaway: h.why_you_care || '',
  source: h.url || h.source || null
}));

const longHorizonOpps = sitrepOpps.filter(o => {
  if (!o.response_deadline) return true;
  const daysOut = Math.ceil((new Date(o.response_deadline) - new Date()) / 86400000);
  return daysOut > 30;
}).slice(0, 6);
const acqNews = longHorizonOpps.map(o => ({
  item: (o.opp_title || 'Opportunity').substring(0, 60),
  status: 'blue',
  update: `${o.agency || 'Agency'} | ${o.stage || 'Active'} | ${o.response_deadline ? 'Due: ' + new Date(o.response_deadline).toLocaleDateString() : 'Long range / TBD'}`,
  takeaway: `Value: ${((parseFloat(o.estimated_value)||0)/1e6).toFixed(1)}M`,
  source: null
}));

const sitrep = {
  strategic_synthesis: briefSummary || `Pipeline: ${stats.total_opps || 0} active opps | ${stats.pursue || 0} PURSUE | ${stats.evaluate || 0} EVALUATE | ${((stats.pipeline_value || 0)/1e6).toFixed(1)}M total value. ${deadlineSoon.length > 0 ? deadlineSoon.length + ' deadlines within 30 days.' : 'No immediate deadlines.'}`,
  pipeline_status: { total: stats.total_opps || 0, pursue: stats.pursue || 0, evaluate: stats.evaluate || 0, pipeline_value: stats.pipeline_value || 0, deadlines_14d: stats.deadlines_14d || 0, summary: `${((stats.pipeline_value||0)/1e6).toFixed(1)}M across ${stats.total_opps||0} active opps` },
  critical_actions: criticalActions,
  top_news: briefHeadlines.slice(0, 5),
  world_news: worldNews,
  market_signals: marketSignals,
  govt_intel: { dod: dodItems, ic: [], dhs: [] },
  acquisition_news: acqNews,
  bluf: criticalActions.length > 0 ? [criticalActions[0]] : ['Pipeline on track — no critical actions today.'],
  summary: briefSummary || null,
  generated_at: new Date().toISOString()
};

delete mega.sitrep_opps;
const payload = JSON.stringify(Object.assign({ status: 'ok', cached_at: new Date().toISOString() }, mega, { sitrep }, kpi ? { kpi } : {}));
return [{ json: { payload } }];
